cy.get('[data-cy="tipo-admin"]').click();
cy.get('[id="email"]').type('admin@uni.edu');
cy.get('[id="password"]').type('contraseña_incorrecta');
cy.get('[data-cy="btn-login"]').click();
// No debe redirigir
cy.url().should('include', '/login');

cy.clearLocalStorage();
cy.visit('/login');
cy.get('[id="email"]').should('exist');
cy.get('[id="password"]').should('exist');
cy.get('[data-cy="btn-login"]').should('exist');

cy.visit('/ruta-inexistente', {
  failOnStatusCode: false
});
// O redirige al login o muestra un 404 controlado
cy.url().should('not.be.empty');

cy.request({
  url: `${API}/estudiantes`,
  failOnStatusCode: false
}).then(resp => {
  expect(resp.status).to.be.oneOf([200, 503]); // 503 si el servidor está apagado
});

cy.wait('@getEstudiantes');
// Verificar que la interfaz carga la lista
cy.get('body').contains(/estudiante|student|EST-/i).should('be.visible');

const estadosValidos = ['Pendiente', 'Aprobada', 'Rechazada', 'Retirada'];
estadosValidos.forEach(estado => {
  cy.request({
    method: 'PUT',
    url: `${API}/matriculas/1/estado?estado=${estado}`,
    failOnStatusCode: false
  }).then(resp => {
    // Puede ser 200 (éxito) o 404 (no encontrado) pero no 400 (estado inválido)
    expect(resp.status).to.not.equal(400);
  });
});

cy.request({
  method: 'PUT',
  url: `${API}/matriculas/1/estado?estado=EstadoInvalido`,
  failOnStatusCode: false
}).then(resp => {
  expect(resp.status).to.be.oneOf([400, 404, 503]);
});

cy.clearLocalStorage();
cy.visit('/dashboard', {
  failOnStatusCode: false
});
cy.url().should('include', '/login');

cy.request({
  url: 'http://127.0.0.1:8000/health',
  failOnStatusCode: false
}).then(resp => {
  if (resp.status === 200) {
    expect(resp.body.status).to.equal('healthy');
  } else {
    cy.log('Backend no disponible - prueba de conectividad omitida');
  }
});

cy.request({
  method: 'POST',
  url: `${API}/auth/login`,
  body: {
    email: 'admin@uni.edu',
    password: 'admin123',
    tipo: 'admin'
  },
  failOnStatusCode: false
}).then(resp => {
  if (resp.status === 200) {
    expect(resp.body.success).to.be.true;
    expect(resp.body.data.tipo).to.equal('admin');
  } else {
    cy.log(`Backend no disponible (status: ${resp.status})`);
  }
});

cy.request({
  method: 'POST',
  url: `${API}/auth/login`,
  body: {
    email: 'admin@uni.edu',
    password: 'WRONG',
    tipo: 'admin'
  },
  failOnStatusCode: false
}).then(resp => {
  if (resp.status !== 503) {
    // Solo verificar si el servidor está activo
    expect(resp.status).to.equal(401);
  }
});

cy.request({
  method: 'POST',
  url: `${API}/auth/login`,
  body: {
    email: 'test@test.com',
    password: 'pass',
    tipo: 'hacker'
  },
  failOnStatusCode: false
}).then(resp => {
  if (resp.status !== 503) {
    expect(resp.status).to.equal(400);
  }
});

cy.intercept('POST', '**/auth/login', {
  forceNetworkError: true
}).as('loginError');
cy.visit('/login');
cy.get('[id="email"]').type('admin@uni.edu');
cy.get('[id="password"]').type('admin123');
cy.get('[data-cy="btn-login"]').click();
// La app debería seguir en /login o mostrar error
cy.url().should('include', '/login');

cy.intercept('GET', '**/api/**', {
  forceNetworkError: true
}).as('apiError');
cy.window().then(win => {
  win.localStorage.setItem('auth', JSON.stringify({
    loggedIn: true,
    userType: 'admin',
    userName: 'Administrador'
  }));
});
cy.visit('/dashboard');
// La app debería seguir cargando sin crash
cy.get('body').should('be.visible');

cy.intercept('GET', '**/api/**', req => {
  req.on('response', res => {
    res.setDelay(1000);
  });
  req.reply({
    success: true,
    data: []
  });
});
cy.window().then(win => {
  win.localStorage.setItem('auth', JSON.stringify({
    loggedIn: true,
    userType: 'admin',
    userName: 'Administrador'
  }));
});
cy.visit('/dashboard');
cy.get('body').should('be.visible');

cy.visit('/login');
cy.get('[id="email"]').type('no-es-un-email');
cy.get('[id="password"]').type('123');
cy.get('[data-cy="btn-login"]').click();
// El navegador debe mostrar validación HTML5 o la app la manejará
cy.url().should('include', '/login');

cy.window().then(win => {
  win.localStorage.setItem('auth', JSON.stringify({
    loggedIn: true,
    userType: 'admin',
    userName: 'Administrador'
  }));
});
cy.visit('/dashboard');
cy.url().should('include', '/dashboard');
// Recargar
cy.reload();
cy.url().should('include', '/dashboard');

cy.window().then(win => {
  win.localStorage.setItem('auth', JSON.stringify({
    loggedIn: true,
    userType: 'admin',
    userName: 'Administrador'
  }));
});
cy.visit('/dashboard');
cy.get('[data-cy="btn-logout"]').click({
  force: true
});
cy.window().then(win => {
  const auth = win.localStorage.getItem('auth');
  expect(auth).to.be.null;
});

